import { FooterToolbar } from '@ant-design/pro-components';
import { FC } from 'react';
import { SptComponentProvider } from '../Provider';
import React from 'react';
import './style/index.less';
import classNames from 'classnames';

type FooterToolbarProps = React.ComponentProps<typeof FooterToolbar>;

export interface SptFooterToolbarProps extends FooterToolbarProps {
    style?: React.CSSProperties;
    className?: string;
    footerToolbarStyle?: React.CSSProperties;
    footerToolbarClassName?: string;
}

/**
 * Pro-components FooterToolbar的封装，解决高度塌陷问题
 * @param param
 * @returns
 */
const SptFooterToolbar: FC<SptFooterToolbarProps> = ({
    children,
    className,
    style,
    footerToolbarStyle,
    footerToolbarClassName,
    ...footerProps
}) => {
    return (
        <SptComponentProvider>
            <div
                className={classNames('spotter-footer-toolbar-container', className)}
                style={style}
            >
                <FooterToolbar
                    className={classNames('footerToolbarClassName')}
                    style={footerToolbarStyle}
                    {...footerProps}
                >
                    {children}
                </FooterToolbar>
            </div>
        </SptComponentProvider>
    );
};

export default SptFooterToolbar;
